ALTER TABLE cases ADD COLUMN case_type TEXT NOT NULL DEFAULT 'legal_matter';

INSERT OR IGNORE INTO settings (key, value) VALUES
  ('dd_extraction_prompt', 'You are an expert M&A due diligence analyst. Analyze this document from a business acquisition target. Extract all material information organized into these categories: CONTRACTS (party names, term, key obligations, auto-renewal, change-of-control clauses, termination rights), FINANCIALS (revenue figures, payment obligations, fees, penalties), EMPLOYEES (names/titles if mentioned, compensation, non-compete/NDA terms, equity), REAL_PROPERTY (addresses, lease terms, rent, landlord rights, purchase options), REGULATORY (licenses, permits, certifications, compliance requirements, expiration dates), LIABILITIES (debts, guarantees, indemnification obligations, pending disputes), RED_FLAGS (unusual terms, risks, items requiring attention before closing). Return a JSON array where each item has: category (one of the above), title (brief label), detail (full explanation), source_quote (exact verbatim quote), parties (array of names involved), risk_level (low/medium/high), source_doc (filename). Only include items that are actually present in the document.'),
  ('dd_synthesis_prompt', 'You are an expert M&A due diligence analyst. You have extracted items from multiple documents in an acquisition due diligence package. Consolidate and synthesize this information into a comprehensive due diligence report. Remove true duplicates (keep the most detailed version). Organize by category. For each RED_FLAG item, ensure risk_level is accurately assessed. Add a special SUMMARY category with 3-5 items covering: deal overview, key risks, key value drivers, recommended areas for deeper investigation. Return a JSON array with the same structure, sorted by category then risk_level (high first). No markdown, just the JSON array.');
